package org.eclipse.rdf4j.sail.lmdb.sketch;

import java.util.function.DoubleUnaryOperator;

/** Focused OMNI witness-set estimation algorithms. */
final class OmniSketchEstimatorService {
	double estimateMembershipRows(OmniWitnessSet source, OmniWitnessSet membership, double sourceRows,
			DoubleUnaryOperator rowNormalizer) {
		if (source == null || source.isEmpty() || membership == null || membership.isEmpty()) {
			return 0.0d;
		}
		int retainedCount = 0;
		for (int i = 0; i < source.retainedWitnessCount(); i++) {
			if (membership.containsHash(source.hashAt(i))) {
				retainedCount++;
			}
		}
		int sourceCount = source.retainedWitnessCount();
		if (sourceCount <= 0) {
			return 0.0d;
		}
		return rowNormalizer.applyAsDouble(sourceRows * ((double) retainedCount / (double) sourceCount));
	}
}
